import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { formatDate } from './formatDate';

describe('formatDate', () => {
  it('should handle happy path: valid ISO string with time', () => {
    const iso = '2023-08-15T12:34:56Z';
    const formatted = formatDate(iso);
    // Expect the function to return the date part in YYYY-MM-DD format
    expect(formatted).toBe('2023-08-15');
  });

  it('should handle edge case: valid ISO string without time component', () => {
    const iso = '2023-01-01';
    const formatted = formatDate(iso);
    // Expect the function to still return the date part correctly
    expect(formatted).toBe('2023-01-01');
  });

  it('should handle null/empty: null, undefined, empty string, 0', () => {
    const onNull = formatDate(null as any);
    const onUndefined = formatDate(undefined as any);
    const onEmpty = formatDate('');
    const onZero = formatDate(0 as any);

    // All inputs should return an empty string or null/undefined consistently
    expect(onNull).toBe('');
    expect(onUndefined).toBe('');
    expect(onEmpty).toBe('');
    expect(onZero).toBe('');
  });
});

